def reverse_string(s):
    i=len(s)-1
    out = ""
    while i>=0:
        out+=s[i]
        i-=1 
    return out

def is_palindrome(s):
    return s==reverse_string(s)
if task == "sum_until_0":
    total = 0
    n = int(input())
    while n !=0: # the terminal condi
        total += n # add n to the total
        n=int(input()) # take the next n form the input
    print(total)

elif task == "total_price":
    total_price = 0
    while True: # repeat forever since we are breaking inside
        line = input()
        if line =="END": # The terminal condition
            break
        quantity, price = line.split() # split uses space by default
        quantity, price = int(quantity),int(price) # convert to ints
        total_price += quantity*price # accumulate the total price
    print(total_price)
elif task == "only_ed_or_ing":
    while True:
        s= input()
        if s.lower()== "stop":
            break
        low=s.lower()
        if low.endswith("ed") or low.endswith("ing"):
            print(s)

elif task == "reverse_sum_palindrome":
    while True:
        s=input()
        if s =="-1":
            break
        n=int(s)
        rev=int(reverse_string(str(n)))
        total = n+rev
        if is_palindrome(str(total)):
            print(n)

elif task == "double_string":
    while True:
        line =input()
        if line =="":
            break
        print(line+line)

elif task == "odd_char":
    result=""
    first=True
    while True:
        line = input()
        part = line[0::2]
        if first:
            result=part
            first=False
        else:
            result+=" "+part
        if line.endswith("."):
            break
    print(result)

elif task == "only_even_squares":
    while True:
        s=input()
        if s == "NAN":
            break
        n=int(s)
        if n%2==0:
            print(n*n)

elif task == "only_odd_lines":
    result=""
    index=-1
    while True:
        line = input()
        if line=="END":
            break
        if index%2 ==1:
            if result=="":
                result=line
            else:
                result =line+"\n"+result
        index+=1
    print (result)

